+// StatusString returns a human-readable description of the pane's execution state.
+func (p Pane) StatusString() string {
+	if !p.Dead {
+		return "running"
+	}
+	if p.DeadStatus == 0 {
+		return "exit 0"
+	}
+	return fmt.Sprintf("exit %d", p.DeadStatus)
+}
